      const { structurePass } = await import('./server/nvm/revision/passes/structure.ts');
      const records = Array.from({ length: 9 }, (_, i) =>
        makeRec(i, i % 2 === 0 ? { seededClueIds: [`c${i}`] } : {}),
      );
